import{_ as p,o as a,c as e,j as r,a as t,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"光剑七式","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/光剑七式.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/光剑七式.md"}'),s={name:"4.资源分区/6.技艺及称号/武技类/白刃类/光剑七式.md"};function n(d,b,i,l,_,h){return a(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"光剑七式",tabindex:"-1"},[t("光剑七式 "),r("a",{class:"header-anchor",href:"#光剑七式","aria-label":'Permalink to "光剑七式"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘003C")])])],-1),o('<h1 id="光剑七式-1" tabindex="-1">光剑七式 <a class="header-anchor" href="#光剑七式-1" aria-label="Permalink to &quot;光剑七式&quot;">​</a></h1><p>绝地武士在早期探索原力与凯伯水晶的共鸣时发现，原力在与凯伯水晶结合后会迸发出巨大的能量，它们相较传统的武器更为危险，致命。于是为了控制这股非凡的能量，绝地武士研创了使用光剑的技巧与方法，这就是光剑战型的由来。在共和国发展的历程中，光剑战型也发展出更多璀璨的结晶。各式不同的战型能有效的帮助绝地武士应对各种危机情况。<br> 光剑战型对绝地武士的而言意义非凡，它们不仅仅是一种战斗技巧，还代表了绝地武士的道德和精神价值观。因为绝地不只是战士，他们同时也是和平维护者，肩负有保护和平与正义的使命。光剑战型在被绝地武士用以自我防卫的同时，还体现了绝地武士们避免无谓杀戮、自我掌控、均衡与和谐、保护弱小的道德原则。</p><p>光剑战型每一式都具有三个阶段：【基要】、【精通】、【掌握】，对于同一式战型人物需要逐级购买。<br> 战型的各阶段额外效果叠加计算。<br> 各阶段战型的价格为：基要—D+500、精通—C+1000、掌握—B+2000</p><p>尽管光剑七式是专门为光剑研发的使用技巧，但人物也可以使用具有【能量武器】特性的剑/刀类形状相似的武器使用这门技艺。</p><p>第一式—希·乔（Shii-Cho）<br> 这一式又被称为索克洛式，是最基础的光剑战型，也更为适合绝地学徒使用。<br> 作为奠定光剑战型的基石，希乔在绝地武士分裂之前就已经广泛普及，它是所有绝地武士的必修课，无论他们擅长何种剑型。<br> 希·乔注重光剑的基本运用与人物内在的均衡，如果学徒能够精通希乔，则他在学习其他光剑技艺时会起到事半功倍的效果。<br> 希·乔最大的特点就是简单直接，剑型以纵向劈砍和横向挥击为主。而富有经验的绝地武士会在使用希乔时配合双腿进行中等幅度的侧向移动，以达到防守与进攻的快速切换。</p><p>动作：标准动作<br> 目标：一个单位<br> 基本效果：对触及范围内的目标进行一次近战攻击，造成挥砍伤害。<br> 额外效果：<br> 基要—<br> 人物在进行此次攻击时获得3点修行加值。<br> 人物在进行此次攻击后可立即以自由动作移动敏捷附加成功米。<br> 如果人物在进行此次攻击后不以本剑型的额外效果进行移动，则人物在防御上获得3点洞察加值，持续一轮；<br> 如果人物在进行此次攻击后以本剑型的额外效果进行移动，则全豁免上获得3点修行加值，持续一轮。<br> 精通—<br> 人物在进行此次攻击时再获得3点修行加值。<br> 人物在进行此次攻击后的下一次移动的距离增加人物本身移动速度的一半米。<br> 如果人物在进行此次攻击后不以本剑型的额外效果进行移动，则人物在防御上再获得3点洞察加值，持续一轮<br> 如果人物在进行此次攻击后以本剑型的额外效果进行移动，则全豁免上再获得3点修行加值，持续一轮。<br> 掌握—<br> 人物在进行此次攻击时再获得感知属性点修行加值，人物在进行此次攻击后的下一次移动的距离再增加人物本身移动速度的一半米。<br> 如果人物在进行此次攻击后不以本剑型的额外效果进行移动，则人物在防御上再获得操控属性点洞察加值，持续一轮；<br> 如果人物在进行此次攻击后以本剑型的额外效果进行移动，则全豁免上再获得沉着属性点修行加值，持续一轮。<br> 特殊的，如果人物精通了希·乔剑型，则每影片结束时，人物会获得2点仅用于学习光剑七式的xp。</p><p>第二式—马卡希（Makashi）<br> 马卡希式强调剑术技巧和优雅的动作，因此绝地武士在使用这一剑型时通常会采用特定的军刀起手式。<br> 马卡希式特点之一是单手持剑。绝地武士通常使用一只手来操控光剑，这使他们更加灵活多变地进行精确的剑术动作。除了单手持剑，使用马卡希式的绝地们通常还挺直脊柱、垫步并轻微弯曲前脚尖，这令绝地武士能够更加快捷的做出反应并迅速而优雅的进行攻击。<br> 使用马卡希式时，绝地武士会单手持剑，手臂高举，剑尖指向对手，并以最快速的动作出剑，在极短时间内优雅的结束战斗。由于马卡希剑型更要求使用者有着流畅而精细的剑术动作，初学者们可能很难发挥出这一式的效果。</p><p>动作：标准动作<br> 目标：触及范围内的一个单位<br> 基本效果：单手持剑，精准而优雅的刺出致胜的一击。对目标进行一次近战攻击，造成穿刺伤害。<br> 额外效果：<br> 基要—<br> 人物在进行此次攻击时无视1点部位减值，若目标先攻低于自己，则这次攻击获得5点高速。<br> 人物进行此次攻击后，先攻提升风度属性点，持续一轮。<br> 精通—<br> 人物在进行此次攻击时再无视4点部位减值，若目标先攻低于自己，则这次攻击再获得10点高速。<br> 进行此次攻击后的一轮内，人物对先攻低于自己的单位可以反射动作打断性的进行一次移动。<br> 掌握—<br> 人物在进行此次攻击时再获得风度属性点高速，若目标先攻低于自己，则这次攻击具有8加骰，并能将攻击上剩余的高速转为破甲或等额的速度加值。<br> 在进行此次攻击后的一轮内，人物对先攻低于自己的单位具有S级先制。</p><p>第三式—索雷苏（Soresu）<br> 索雷苏式强调是坚韧与防护的一式，绝地武士常使用于这一式面对多个敌人攻击，以保护自己和无辜者。<br> 索雷苏式是绝地武士发展出的专门用以自我防御的剑型，也是绝地武士“我不犯人”哲学的体现。<br> 在学徒阶段，练习者需要学习有效的防御姿势和如何以光剑应对远程攻击。而精通索雷苏式的绝地武士可以更好地应对多个敌人的攻击，他们已经掌握了如何有效地使用光剑来保护自己。</p><p>动作：标准动作<br> 目标：自身<br> 基本效果：将光剑风车般挥舞，最大限度的防护自身易于受击之处，进行一次全力防御。<br> 额外效果：<br> 基要—<br> 人物在一轮内获得2点格挡防御与2点闪避防御。<br> 人物若能精确定位一个单位，则该单位对人物进行远程攻击时，远程武器模板与能量武器附带的【高速】无法生效。<br> 精通—<br> 人物在一轮内再获得3点格挡防御与3点闪避防御，并同时进行格挡。<br> 应对远程攻击时，人物可对触及范围内的单位提供全遮蔽。<br> 掌握—<br> 人物在使用剑型时可将自身具有的格挡防御在一轮内转化为闪避防御；或是将自身具有的闪避防御在一轮内转化为格挡防御，转化防御的合计值不能超过人物的沉着属性。人物在一轮内再获得5点格挡防御与闪避防御以及基于二者中较低者的【坚韧】。<br> 使用剑型后的一轮内仅一次，当人物受到近战攻击后，若这次攻击不对人物造成任何伤害，则人物可以反射动作立即对攻击目标进行一次近战反击，这次反击可以将计算此次攻击破除防御后剩余的闪避防御与格挡防御中较低者作为技艺加值加入其中。</p><p>第四式—阿塔鲁（Ataru）<br> 阿塔鲁式是极其注重技巧、运动的剑型。想要流畅运用阿塔鲁式，使用者需能够灵敏地在狭小的空间中进行跳跃、辗转腾挪并进行一系列精巧而复杂的动作。<br> 学习此剑型的学徒可以借此进行迅速移动、跳跃、对敌人发起快速攻击。然而，初学者的技巧可能相对简单，缺乏更高级的剑术技巧。<br> 而精通此剑型的绝地武士通常会使用这些技巧来穿越战场、躲避攻击、快速接近敌人或进行空中打击。毫无疑问的，阿塔鲁式增加了他们的机动性和战斗方式。</p><p>动作：标准动作<br> 目标：触及范围内的一个单位<br> 基本效果：弯曲身体，进行跳跃并在此过程中借助身体的扭动更快速的挥出光剑。对目标进行一次近战攻击，造成挥砍伤害。<br> 额外效果：<br> 基要—<br> 人物在进行此次攻击前或者进行此次攻击后可以进行一次跳跃检定，并移动成功数米的距离。<br> 若人物在进行此次攻击前进行跳跃，则此次攻击获得3点技艺加值。<br> 若人物在进行此次攻击后进行跳跃，则人物的运动检定在一轮内获得3点洞察加值。<br> 精通—<br> 使用此剑型的一轮内，人物以跳跃检定进行移动时，该检定每有1个成功数人物就能额外移动10米，每轮以此方式获得的额外移动距离至多为人物的移动速度。<br> 若人物在进行此次攻击前以本剑型提供的方式进行跳跃，则此次攻击可对跳跃路径上所有敌方单位进行此次攻击，并再获得3点技艺加值。<br> 若人物在进行此次攻击后以本剑型提供的方式进行跳跃，则人物的运动检定在一轮内再获得3点洞察加值。<br> 掌握—<br> 现在人物在进行此次攻击前与进行此次攻击后皆可进行一次跳跃检定，并移动成功数米的距离。<br> 当人物在进行此次攻击前以本剑型提供的方式进行跳跃，此次攻击再获得跳跃检定成功数点技艺加值。<br> 当人物在进行此次攻击后以本剑型提供的方式进行跳跃，则人物的运动检定在一轮内再获得跳跃检定成功数点洞察加值。</p><p>特殊的，人物使用阿塔鲁式每进行一次跳跃，都需要消耗1点原力或者承受1点不可豁免的疲乏点数。</p><p>第五式—希恩（Shien）/德杰姆·索（Djem so）<br> 前置：习得第三式—索雷苏式的基要用法（希恩）/习得第四式—阿塔鲁式的基要用法（德杰姆·索）<br> 第五式具有两种形式，绝地武士可以根据自己需求学习其中的任意一种。</p><p>希恩（Shien）<br> 希恩式是由第三式—索雷苏的剑型风格演化而来的剑型，其本身一定程度的摒弃了索雷苏式全面防守的风格，转而偏向柔中带刚的防守反击形式。<br> 此外，希恩式还能有效帮助绝地武士抵御爆能枪这一类新式武器的攻击并借助光剑将子弹回敬给对手。</p><p>需求：处于格挡状态<br> 动作：标准动作<br> 目标：自身<br> 基本效果：挥舞光剑抵挡各式攻击，伺机寻找对手进攻间隙的破绽从而出奇制胜。在回合外受到近战攻击后，可以使用反射动作对攻击方以光剑进行反击，当人物以此效果进行反击后，需再度消耗标准动作以进行准备才能进行下一次反击。<br> 额外效果：<br> 基要—<br> 人物在一轮内获得2点格挡防御并具有基于格挡防御的【防能量武器】，在一轮内进行的攻击获得2个附加成功。<br> 精通—<br> 人物在一轮内再获得5点格挡防御，在一轮内进行的攻击再获得2个附加成功。<br> 当人物在一轮内受到远程能量武器的攻击时，若这次攻击不对人物造成任何伤害，人物可以反射动作将这次攻击目标偏转为敏感范围内的任意一个目标，被偏转攻击的射程等同原攻击方的射程，被偏转的攻击检定等同于你光剑的攻击检定。计算射程时，将原攻击方至人物的距离与人物至偏转目标的距离合并计算。被偏转攻击对目标的定位等级取决于人物而非原攻击方。若人物如此做，则视为人物已经以本剑型的基本效果进行反击。<br> 掌握—<br> 每轮一次，人物在一轮内受到攻击时，除本剑型的基本效果外，可以反射动作再进行额外的一次反击。<br> 人物在一轮内再获得8点格挡防御，在一轮内进行的攻击再获得8个附加成功。</p><p>德杰姆·索（Djem so）<br> 德杰姆·索式是在绝地维护银河系和平任务日益繁重的背景下，部分绝地认为第三式所带来的局面过于被动而创造出的剑型。由于注重攻击，一部分绝地武士认为这一式助长了不正当的控制欲望；而研习此剑型的绝地武士则认为，这是“和平需要以武力作为后盾”的必然。<br> 这一式强调更加强大的进攻，需要绝地武士将光剑用于坚定的进攻，进而迅速的压制敌人的防御。</p><p>动作：标准动作<br> 目标：触及范围内的一个目标<br> 基本效果：对目标进行全力攻击，造成挥砍伤害。<br> 额外效果：<br> 基要—<br> 人物在进行此次攻击时获得4点增强加值。目标每受到此剑型造成的一次伤害，其闪避/格挡/洞察/偏斜防御中数值最高的那一项都会减少2点，这一减值会在目标不再受此剑型伤害的一轮后移除。<br> 精通—<br> 人物在进行此次攻击时再获得4点增强加值。目标每受到此剑型造成的一次伤害，其闪避/格挡/洞察/偏斜防御中数值最高的那一项都会再减少2点，这一减值会在目标不再受此剑型伤害的一轮后移除。受到伤害的目标会在一轮内陷入B级别创伤来源的困难地形影响。<br> 掌握—<br> 人物在进行此次攻击时再获得力量属性点增强加值。目标每受到此剑型造成的一次伤害，其闪避/格挡/洞察/偏斜防御中数值最高的那一项都会再减少6点，这一减值会在目标不再受此剑型伤害的一轮后移除。<br> 受到伤害的目标会在一轮内陷入A级别创伤来源的困难地形影响。</p><p>第六式—尼曼（Niman）<br> 前置：习得第一式—希·乔式、第三式—索雷苏式、第四式—阿塔鲁式三者中至少二者的基要用法。<br> 这是一种讲究原力平衡性的剑法，其剑法具有中庸和平衡的特点。也因此，这一式剑法虽然掌握难度较高，但其不适合用于争斗厮杀。<br> 尼曼式注重化解冲突暴力，力求令争斗双方停止攻击。许多善于外交的绝地武士更推崇此剑型。<br> 动作：标准动作<br> 目标：触及范围内至多二个目标<br> 基本效果：谨慎而周到的挥舞光剑，以光剑对目标进行一次攻击，造成挥砍伤害，这次攻击可以转换为击落武器。</p><p>额外效果：<br> 基要—<br> 人物的攻击、防御、全豁免在一轮内获得2点神圣加值。人物可以任意留手攻击所造成的伤害。<br> 精通—<br> 人物的攻击、防御、全豁免在一轮内再获得4点神圣加值。<br> 人物如果在留手攻击/击落武器后结束了一场战斗，则人物在后续的社交检定中获得3个附加成功。<br> 掌握—<br> 人物的攻击、防御、全豁免在一轮内再获得8点神圣加值。<br> 每轮一次，人物在进行此次攻击时，可将这次攻击改为击落武器，若如此做，人物会立即进行一次移动同时对移动路径上的所有目标皆进行击落武器检定。在表现上，绝地武士在人群中斡旋迂回，以光剑巧妙的将陷入争斗的众人武器击落。</p><p>第七式—朱尤（Juyo）/瓦帕德（Vaapad）</p><p>第七式是所有剑型中最为困难、也最为强大的剑型。朱尤与瓦帕德虽然是两种剑型，但它们同属一脉，因此被统称为第七式剑型。朱尤与瓦帕德被认为是所有剑型中最为狂暴、充满争议的一式剑型，它们对使用者的情绪与原力控制能力要求极高。</p><p>朱尤（Juyo）<br> 前置：至少具有其他两种剑型的基要用法，其中必须包含第五式—德杰姆·索式、沉着8<br> 由于西斯帝国的文献资料被绝地武士大量销毁，因此朱尤的具体起源已无从考证。但有绝地大师推测，它可能是西斯武士崛起前，由堕落的黑暗绝地武士在研习黑暗原力时所创造的一种剑型。<br> 朱尤是第七式中最为极端化的剑型，它极端的强调攻击性，并力求使用者将自己的负面情绪放大，利用这种不受控制的负面情绪来激发剑型的最大威力。正因如此，朱尤与黑暗原力相性极佳，也成为了西斯武士的独有剑型。有部分性格极端的绝地武士也使用过朱尤进行战斗，但最后他们基本都被黑暗原力吞噬了心智，彻底堕落为了西斯武士。<br> 朱尤的使用者往往彻底放弃了防御，以毫不停顿的剑招向敌人发起狂风暴雨般的攻击，对手往往刚刚抵挡了朱尤的斩击，下一式刺击便接踵而至。更有甚者，会借助假动作欺骗对手并从意想不到的角度将光剑送入对手心脏。</p><p>动作：标准动作<br> 目标：触及范围内的一个单位<br> 基本效果：以狂暴的姿态挥舞光剑，对目标进行一次全力攻击，这次全力攻击可额外减少2点基础防御，并额外获得2点增强加值，造成穿刺或挥砍伤害。<br> 额外效果：<br> 基要—<br> 每轮一次，人物在发起攻击前可进行一次虚招，若虚招成功，在虚招减值的基础上还会陷入C级别措手不及状态，持续一轮。<br> 人物在进行此次攻击时，若承受了至少1点亢奋异常点数，则人物进行此次攻击时会获得3点表现加值。<br> 精通—<br> 本剑型带来的措手不及提升至B级。<br> 人物现在可以选择减少任意点闪避/格挡/偏斜防御并获得等于所减少防御数值的高速/威猛/破魔，减少的防御值至多等于人物的沉着属性值。<br> 人物在进行此次攻击时，每承受1点亢奋异常点数，人物在进行此次攻击时就获得1点表现加值，获得表现加值的上限为人物的沉着属性值。<br> 掌握—本剑型带来的措手不及提升至A级。<br> 每轮一次，人物以本剑型攻击后可立即对触及范围内的目标再进行一次相同的攻击。</p><p>特殊的，人物每使用朱尤两轮，就需要进行一次意志豁免，DC为24-人物的沉着属性，失败则需要承受差值的亢奋情绪异常点数。</p><p>瓦帕德（Vaapad）<br> 前置：至少具有其他两种剑型的基要用法、沉着8<br> 瓦帕德的发明者是著名的绝地大师—梅斯温杜。鉴于朱尤过分依赖黑暗原力的特性令其并不适合西斯以外的人使用，因此梅斯温杜对它做出大量修改，瓦帕德剑型也就此诞生。新的瓦帕德剑型对原力的依赖性更低，相比极端追求进攻性的朱尤，瓦帕德的剑招更为完善。但即便如此，瓦帕德的核心依然是以负面情绪为主，在战斗时使用者往往会游走在黑暗原力的边缘。而由于剑型本身倾向将内心的愤怒情绪调动并运用在攻击上，它仍然被众多绝地武士认为是一柄过于危险的武器。<br> 瓦帕德剑型要求使用者必须将自身内心的阴暗面力量为自身所用，若控制不佳，它可能会令使用者在不知不觉中偏离原力的光明面，坠入黑暗。</p><p>动作：标准动作<br> 目标：触及范围内的一个单位<br> 基本效果：对目标进行一次全力攻击，这次全力攻击带来的基础防御减值-1，造成挥砍伤害。<br> 额外效果：<br> 基要—<br> 在进行此次攻击前，你可以对目标进行一次冲撞，若目标对抗失败，其将不会被击退而是在一轮内移动速度减少失败数米。<br> 人物进行此次攻击时获得5点威猛。<br> 精通—<br> 目标在对抗冲撞检定失败后，会被打乱架势，在一轮内减少50米移动速度；且无法享受格挡带来的好处，这是C级别创伤来源的效果。<br> 人物进行此次攻击时再获得5点威猛。<br> 掌握—<br> 目标在对抗冲撞检定失败后，会被打乱架势，在一轮内并处于B级别创伤来源的定身状态。<br> 人物在进行此次攻击上获得等于沉着属性值的威猛。<br> 计算防御后，如果目标不保留任何格挡/洞察/掩蔽防御，则你可将剩余的威猛转化为等额的破魔或攻击上的增强加值。</p><p>特殊的，人物每使用瓦帕德两轮，就需要进行一次意志豁免，DC为18-人物的沉着属性，失败则需要承受差值的亢奋情绪异常点数。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',30)])])}const f=p(s,[["render",n]]);export{m as __pageData,f as default};
